closes = [float(c['close']) for c in d['data']['ohlc']]
highs = [float(c['high']) for c in d['data']['ohlc']]
lows = [float(c['low']) for c in d['data']['ohlc']]

current = closes[-1]
week_high = max(highs)
week_low = min(lows)
week_range = week_high - week_low

# Simple moving averages
def sma(data, period):
    if len(data) < period:
        return None
    return sum(data[-period:]) / period

ma20 = sma(closes, 20)
ma50 = sma(closes, 50)
ma100 = sma(closes, 100)

